def seed_db():
    events = json.loads(EVENTS_JSON)
    with get_conn() as conn:
        existing = conn.execute("SELECT COUNT(*) FROM events").fetchone()[0]
        if existing > 0:
            return
        now_str = datetime.now(timezone.utc).strftime("%Y-%m-%dT%H:%M:%SZ")
        for e in events:
            try:
                conn.execute("""
                    INSERT INTO events
                      (event_id, store_id, camera_id, visitor_id, event_type,
                       timestamp, zone_id, dwell_ms, is_staff, confidence,
                       queue_depth, sku_zone, session_seq, ingested_at)
                    VALUES (?,?,?,?,?,?,?,?,?,?,?,?,?,?)
                """, (
                    e["event_id"], e["store_id"], e["camera_id"], e["visitor_id"],
                    e["event_type"], e["timestamp"], e.get("zone_id"),
                    e.get("dwell_ms", 0), int(e.get("is_staff", False)),
                    e.get("confidence", 0.9),
                    e.get("metadata", {}).get("queue_depth"),
                    e.get("metadata", {}).get("sku_zone"),
                    e.get("metadata", {}).get("session_seq", 0),
                    now_str,
                ))
                conn.execute("""
                    INSERT INTO health_log(store_id, last_event_ts, updated_at)
                    VALUES (?, ?, ?)
                    ON CONFLICT(store_id) DO UPDATE SET
                        last_event_ts = excluded.last_event_ts,
                        updated_at = excluded.updated_at
                """, (e["store_id"], e["timestamp"], now_str))
            except Exception:
                pass
    print(f"[INFO] Seeded {len(events)} events into database")
